import json

def print_model_ids(json_str: str):
    try:
        data = json.loads(json_str)
    except json.JSONDecodeError as e:
        print("JSON 解析失败：", e)
        return

    if not isinstance(data, list):
        print("输入的 JSON 不是一个数组")
        return

    for item in data:
        model_id = item.get("id")
        if model_id:
            print(model_id)

